import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is inflation?", a: "Inflation is the rate at which prices rise over time, reducing how much goods and services your money can buy." },
  { q: "How is inflation measured?", a: "Inflation is commonly measured with price indexes such as CPI, which tracks changes in the cost of a basket of consumer goods and services." },
  { q: "What is CPI?", a: "CPI stands for Consumer Price Index. It is a widely used measure of consumer price changes and purchasing power over time." },
  { q: "How does inflation affect savings?", a: "Inflation reduces the real value of cash savings. If savings earn less than inflation, purchasing power falls over time." },
  { q: "What is hyperinflation?", a: "Hyperinflation is extremely rapid inflation where prices rise so fast that money quickly loses practical value." },
];

const CPI: Record<number, number> = {
  1970: 38.8, 1980: 82.4, 1990: 130.7, 2000: 172.2, 2010: 218.1, 2020: 258.8, 2024: 313.7, 2025: 321.0, 2026: 328.0,
};
const ANNUAL_RATE: Record<number, number> = { 1970: 5.8, 1980: 13.5, 1990: 5.4, 2000: 3.4, 2010: 1.6, 2020: 1.2, 2024: 2.9 };
const money = (value: number, digits = 2) => formatCurrencyValue(value, { maximumFractionDigits: digits });

function interpolateCpi(year: number) {
  if (CPI[year]) return CPI[year];
  const years = Object.keys(CPI).map(Number).sort((a, b) => a - b);
  const before = [...years].reverse().find((item) => item <= year) || years[0];
  const after = years.find((item) => item >= year) || years[years.length - 1];
  if (before === after) return CPI[before];
  const ratio = (year - before) / (after - before);
  return CPI[before] + (CPI[after] - CPI[before]) * ratio;
}

export default function InflationCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(1000);
  const [startYear, setStartYear] = useState(2000);
  const [endYear, setEndYear] = useState(2026);
  const startCpi = interpolateCpi(startYear);
  const endCpi = interpolateCpi(endYear);
  const adjustedValue = startCpi ? amount * (endCpi / startCpi) : amount;
  const cumulativeInflation = startCpi ? (endCpi / startCpi - 1) * 100 : 0;
  const purchasingPowerLoss = adjustedValue - amount;
  const rows = [1970, 1980, 1990, 2000, 2010, 2020, 2024].map((year) => {
    const value = 1000 * (interpolateCpi(2026) / interpolateCpi(year));
    return { year, value, rate: ANNUAL_RATE[year] || 0, cumulative: (interpolateCpi(2026) / interpolateCpi(year) - 1) * 100 };
  });
  const pathRows = Array.from({ length: Math.abs(endYear - startYear) + 1 }, (_, index) => {
    const direction = endYear >= startYear ? 1 : -1;
    const year = startYear + index * direction;
    const value = amount * (interpolateCpi(year) / startCpi);
    return { year, value, loss: value - amount };
  });
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead title="Free Inflation Calculator Online - Calculate Purchasing Power and Inflation Rate Instantly | CalcHive" description="Free online inflation calculator. Calculate the inflation-adjusted value of any amount across any years using US CPI data instantly. 100% free, no signup required." canonical="/inflation-calculator" keywords="free inflation calculator, purchasing power calculator free online, CPI inflation calculator free, calculate inflation rate free, inflation adjusted value calculator free" category="Financial Calculators" breadcrumbName="Free Inflation Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Inflation Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate the inflation-adjusted value of money across years and see how purchasing power changes over time.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Amount</label><input type="number" min="0" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Start year</label><input type="number" min="1970" max="2026" value={startYear} onChange={(e) => setStartYear(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">End year</label><input type="number" min="1970" max="2026" value={endYear} onChange={(e) => setEndYear(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${amount}-${startYear}-${endYear}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Inflation-Adjusted Value</p><p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-inflation">{money(adjustedValue)}</p></div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Purchasing power change", money(purchasingPowerLoss)], ["Cumulative inflation", `${cumulativeInflation.toFixed(1)}%`], ["CPI ratio", `${(endCpi / startCpi).toFixed(2)}x`]].map(([label, value]) => <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">{label}</p><p className="text-lg font-extrabold text-foreground">{value}</p></div>)}</div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Inflation and Purchasing Power for Free</h2><p className="text-muted-foreground leading-relaxed">This CPI inflation calculator free compares CPI values between two years to estimate how prices and purchasing power changed.</p>
          <h2 className="text-2xl font-bold text-foreground">How Inflation Erodes the Value of Money Over Time</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Purchasing Power of $1,000 Over the Years</caption><thead className="bg-muted/60"><tr>{["Year", "Value in Today's Dollars", "Inflation Rate That Year", "Cumulative Inflation"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row.year} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{money(row.value)}</td><td className="py-2.5 px-3">{row.rate.toFixed(1)}%</td><td className="py-2.5 px-3">{row.cumulative.toFixed(1)}%</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free CPI Purchasing Power Calculator for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Purchasing Power Loss Over Time</caption><thead className="bg-muted/60"><tr>{["Year", "Adjusted Value", "Change From Start"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{pathRows.map((row) => <tr key={row.year} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold">{row.year}</td><td className="py-2.5 px-3">{money(row.value)}</td><td className="py-2.5 px-3">{money(row.loss)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/inflation-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


